let animationId;

function animate(timestamp) {
  // DOMを更新
  element.style.transform =
    `translateX(${Math.sin(timestamp / 500) * 100}px)`;

  // 次のフレームをリクエスト
  animationId = requestAnimationFrame(animate);
}

// 開始
