// 非同期ジェネレーター
async function* fetchPages(baseUrl) {
  let page = 1;
  let hasMore = true;

  while (hasMore) {
    const res = await fetch(`${baseUrl}?page=${page}`);
    const data = await res.json();
    yield data.items;
    hasMore = data.hasNext;
    page++;
  }
}

// for await...of で消費
for await (const items of fetchPages('/api/users')) {
  items.forEach(user => renderUser(user));
}

